local function configure_linked_geometry()
 local ri=simion.wb.instances[1]
 local ai=simion.wb.instances[2]
 local ti=simion.wb.instances[3]
 local di=simion.wb.instances[4]
 local half_x=(ai.pa.nx-1)*ai.pa.dx_mm*ai.scale/2
 local half_y=(ai.pa.ny-1)*ai.pa.dy_mm*ai.scale/2
 local accelerator_expected_z=-accelerator_repeller_thickness_mm-
   accelerator_rear_insulation_gap_mm-accelerator_shield_wall_mm+
   accelerator_assembly_translation_z_mm
 assert(math.abs(accelerator_repeller_front_z_mm-
   accelerator_assembly_translation_z_mm)<1e-12,
   'repeller front must follow accelerator assembly translation')
 assert(math.abs(accelerator_grid1_z_mm-accelerator_repeller_front_z_mm-
   accelerator_stage1_length_mm)<1e-12,
   'grid1 must follow accelerator stage1 length')
 assert(math.abs(accelerator_grid2_z_mm-accelerator_grid1_z_mm-
   accelerator_stage2_length_mm)<1e-12,
   'grid2 must follow accelerator stage2 length')
 assert(math.abs(detector_active_plane_z_mm-accelerator_grid2_z_mm-
   accelerator_focus_drift_mm)<1e-12,
   'detector active plane must equal the derived accelerator time-focus plane')
 assert(math.abs(reflectron_entgrid_z_mm-detector_active_plane_z_mm-
   field_free_one_way_length_mm)<1e-12,
   'reflectron entrance must follow the baseline one-way flight length')
 assert(math.abs(reflectron_midgrid_z_mm-reflectron_entgrid_z_mm-
   reflectron_stage1_length_mm)<1e-12,
   'reflectron middle grid must follow stage1 length')
 assert(math.abs(reflectron_backplate_z_mm-reflectron_midgrid_z_mm-
   reflectron_stage2_length_mm)<1e-12,
   'reflectron backplate must follow stage2 length')
 assert(math.abs(accelerator_instance_z_mm-accelerator_expected_z)<1e-12,
   'accelerator instance z must follow repeller rear gap and shield wall')
 assert(accelerator_pa_back_margin_mm>=0,
   'accelerator PA back margin must be nonnegative')
 assert(accelerator_pa_grid_phase_z_mm>=0 and
        accelerator_pa_grid_phase_z_mm<ai.pa.dz_mm,
   'accelerator PA grid phase must be in [0,dz)')
 ai.x,ai.y,ai.z=accelerator_axis_x_mm-half_x,accelerator_axis_y_mm-half_y,
   accelerator_instance_z_mm-accelerator_pa_back_margin_mm-
   accelerator_pa_grid_phase_z_mm
 local near_bore_z=accelerator_repeller_front_z_mm-accelerator_repeller_thickness_mm-
   accelerator_rear_insulation_gap_mm-accelerator_shield_wall_mm-
   flight_tube_near_endcap_gap_mm
 local near_outer_z=near_bore_z-flight_tube_endcap_thickness_mm
 local far_bore_z=reflectron_backplate_z_mm+
   reflectron_backplate_thickness_mm+flight_tube_far_endcap_gap_mm
 local far_outer_z=far_bore_z+flight_tube_endcap_thickness_mm
 local expected_radius=flight_tube_inner_radius_mm+flight_tube_shield_wall_mm
 local tube_axial_span=(ti.pa.nx-1)*ti.pa.dx_mm*ti.scale
 local tube_radial_span=(ti.pa.ny-1)*ti.pa.dy_mm*ti.scale
 local refl_axial_span=(ri.pa.nx-1)*ri.pa.dx_mm*ri.scale
 local refl_radial_span=(ri.pa.ny-1)*ri.pa.dy_mm*ri.scale
 assert(tube_axial_span+1e-9>=reflectron_entgrid_z_mm-near_outer_z,
   'flight-tube PA does not reach the reflectron interface')
 assert(refl_axial_span+1e-9>=far_outer_z-reflectron_entgrid_z_mm,
   'reflectron PA does not contain the far shield end cap')
 assert(tube_radial_span+1e-9>=expected_radius and
        refl_radial_span+1e-9>=expected_radius,
   'shield PA radial span is smaller than the linked outer radius')
 ri.x,ri.y,ri.z=reflectron_axis_x_mm,reflectron_axis_y_mm,reflectron_entgrid_z_mm
 ri.az,ri.el,ri.rt,ri.scale=-90,0,0,1
 ti.x,ti.y,ti.z=0,0,near_outer_z
 ti.az,ti.el,ti.rt,ti.scale=-90,0,0,1
 detector_x_mm=-accelerator_axis_x_mm+detector_mirror_offset_x_mm
 detector_y_mm=-accelerator_axis_y_mm+detector_mirror_offset_y_mm
 detector_z_mm=detector_active_plane_z_mm
 local detector_half_x=(di.pa.nx-1)*di.pa.dx_mm*di.scale/2
 local detector_half_y=(di.pa.ny-1)*di.pa.dy_mm*di.scale/2
 local detector_span_z=(di.pa.nz-1)*di.pa.dz_mm*di.scale
 local expected_detector_span_z=detector_marker_front_margin_z_mm+
   detector_marker_absorber_thickness_mm+detector_marker_back_margin_z_mm
 assert(math.abs(detector_span_z-expected_detector_span_z)<1e-9,
   'detector marker PA z span does not match linked numerical parameters')
 di.x=detector_x_mm-detector_half_x
 di.y=detector_y_mm-detector_half_y
 di.z=detector_z_mm-detector_marker_back_margin_z_mm-
   detector_marker_absorber_thickness_mm
 if trajectory_log_enable~=0 then
  print(string.format('TRACE: linked_geometry accelerator_axis=(%.12g,%.12g) accelerator_instance=(%.12g,%.12g,%.12g) accelerator_cell=(%.12g,%.12g,%.12g) shield_inner_outer_radius=(%.12g,%.12g) shield_bore_z=(%.12g,%.12g) shield_outer_z=(%.12g,%.12g) detector_active_plane=(%.12g,%.12g,%.12g) radius=%.12g marker_thickness=%.12g marker_margins_front_back=(%.12g,%.12g) detector_instance=(%.12g,%.12g,%.12g)',accelerator_axis_x_mm,accelerator_axis_y_mm,ai.x,ai.y,ai.z,ai.pa.dx_mm,ai.pa.dy_mm,ai.pa.dz_mm,flight_tube_inner_radius_mm,expected_radius,near_bore_z,far_bore_z,near_outer_z,far_outer_z,detector_x_mm,detector_y_mm,detector_z_mm,detector_radius_mm,detector_marker_absorber_thickness_mm,detector_marker_front_margin_z_mm,detector_marker_back_margin_z_mm,di.x,di.y,di.z))
 end
end
-- Instance 3 contains the continuous grounded shell, but its cylindrical
-- bounding box overlaps the orthogonal accelerator and the reflectron.
-- Suppress it there so SIMION falls through to the corresponding detailed PA.
function segment.instance_adjust()
 if type(ion_pz_mm)~='number' or type(ion_instance)~='number' then return end
 if ion_instance==3 and
    (ion_pz_mm<=math.max(accelerator_grid2_z_mm,detector_active_plane_z_mm) or
     ion_pz_mm>=reflectron_entgrid_z_mm) then
  ion_instance=0
 end
end
function segment.initialize_run()
 sim_trajectory_quality=trajectory_quality
 local ai=simion.wb.instances[2]
 if accelerator_pa_override and accelerator_pa_override~='' and not accelerator_pa_override_loaded then
  ai.pa:load(accelerator_pa_override)
  ai:_debug_update_size()
  accelerator_pa_override_loaded=true
  if trajectory_log_enable~=0 then
   print(string.format('TRACE: accelerator_pa_override=%s dimensions=%dx%dx%d cell=(%.12g,%.12g,%.12g)',accelerator_pa_override,ai.pa.nx,ai.pa.ny,ai.pa.nz,ai.pa.dx_mm,ai.pa.dy_mm,ai.pa.dz_mm))
  end
 end
 assert(#simion.wb.instances==4, 'formal workbench must contain four PA instances')
 local r,a,t,d=simion.wb.instances[1].pa,ai.pa,simion.wb.instances[3].pa,simion.wb.instances[4].pa
 configure_linked_geometry()
 if accelerator_fast_adjust_enable~=0 then
  local accelerator_voltages={[1]=V_repeller,[2]=V_grid1}
  for ring_index=1,accelerator_ring_count do
   accelerator_voltages[2+ring_index]=
    V_grid1*(accelerator_ring_count+1-ring_index)/(accelerator_ring_count+1)
  end
  accelerator_voltages[3+accelerator_ring_count]=0
  accelerator_voltages[4+accelerator_ring_count]=0
  a:fast_adjust(accelerator_voltages)
 end
 local reflectron_voltages={[1]=0}
 for ring_index=1,reflectron_stage1_ring_count do
  reflectron_voltages[1+ring_index]=
   V_mid*ring_index/(reflectron_stage1_ring_count+1)
 end
 local midgrid_electrode=2+reflectron_stage1_ring_count
 reflectron_voltages[midgrid_electrode]=V_mid
 for ring_index=1,reflectron_stage2_ring_count do
  reflectron_voltages[midgrid_electrode+ring_index]=V_mid+
   (V_backplate-V_mid)*ring_index/(reflectron_stage2_ring_count+1)
 end
 reflectron_voltages[midgrid_electrode+reflectron_stage2_ring_count+1]=V_backplate
 reflectron_voltages[midgrid_electrode+reflectron_stage2_ring_count+2]=0
 r:fast_adjust(reflectron_voltages)
 t:fast_adjust{[1]=0}
 d:fast_adjust{[1]=0}
 if trajectory_log_enable~=0 then
  print(string.format('TRACE: pa_mesh reflectron=%dx%dx%d@(%.12g,%.12g,%.12g) accelerator=%dx%dx%d@(%.12g,%.12g,%.12g) flight_tube=%dx%dx%d@(%.12g,%.12g,%.12g) detector=%dx%dx%d@(%.12g,%.12g,%.12g)',r.nx,r.ny,r.nz,r.dx_mm,r.dy_mm,r.dz_mm,a.nx,a.ny,a.nz,a.dx_mm,a.dy_mm,a.dz_mm,t.nx,t.ny,t.nz,t.dx_mm,t.dy_mm,t.dz_mm,d.nx,d.ny,d.nz,d.dx_mm,d.dy_mm,d.dz_mm))
  print(string.format('TRACE: field_mode accelerator_fast_adjust=%d ideal_accel=%d ideal_stage1=%d ideal_stage2=%d trajectory_quality=%d',accelerator_fast_adjust_enable,ideal_accel_enable,ideal_refl_stage1_enable,ideal_refl_stage2_enable,sim_trajectory_quality))
 end
end
local function grid_planes()
 local electrode_half=accelerator_bore_half_mm+accelerator_ring_width_mm
 local shield_inner_half=electrode_half+accelerator_insulation_gap_mm
 return {
  {name='grid1',group='accelerator',z=accelerator_grid1_z_mm,shape='square',cx=accelerator_axis_x_mm,cy=accelerator_axis_y_mm,half=electrode_half},
  {name='grid2',group='accelerator',z=accelerator_grid2_z_mm,shape='square',cx=accelerator_axis_x_mm,cy=accelerator_axis_y_mm,half=shield_inner_half},
  {name='entgrid',group='reflectron',z=reflectron_entgrid_z_mm,shape='circle',cx=reflectron_axis_x_mm,cy=reflectron_axis_y_mm,radius=flight_tube_inner_radius_mm},
  {name='midgrid',group='reflectron',z=reflectron_midgrid_z_mm,shape='circle',cx=reflectron_axis_x_mm,cy=reflectron_axis_y_mm,radius=reflectron_grid_radius_mm}
 }
end
local function inside_grid(g,x,y)
 local dx,dy=x-g.cx,y-g.cy
 if g.shape=='square' then return math.abs(dx)<=g.half and math.abs(dy)<=g.half end
 return dx*dx+dy*dy<=g.radius*g.radius
end
function segment.efield_adjust()
 local z,E,axis=ion_pz_mm,nil,nil
 if ideal_accel_enable~=0 then
  if z>=accelerator_repeller_front_z_mm and z<accelerator_grid1_z_mm then
   E=(V_repeller-V_grid1)/(accelerator_grid1_z_mm-accelerator_repeller_front_z_mm); axis='z'
  elseif z>=accelerator_grid1_z_mm and z<accelerator_grid2_z_mm then
   E=V_grid1/(accelerator_grid2_z_mm-accelerator_grid1_z_mm); axis='z'
  end
 end
 if ideal_refl_stage1_enable~=0 and z>=reflectron_entgrid_z_mm and z<reflectron_midgrid_z_mm then
  E=-V_mid/(reflectron_midgrid_z_mm-reflectron_entgrid_z_mm); axis='x'
 end
 if ideal_refl_stage2_enable~=0 and z>=reflectron_midgrid_z_mm and z<reflectron_backplate_z_mm then
  E=-(V_backplate-V_mid)/(reflectron_backplate_z_mm-reflectron_midgrid_z_mm); axis='x'
 end
 if E then
  ion_dvoltsx_gu=0
  ion_dvoltsy_gu=0
  ion_dvoltsz_gu=0
  local pi=simion.wb.instances[ion_instance]
  if axis=='x' then ion_dvoltsx_gu=-E*pi.pa.dx_mm*pi.scale else ion_dvoltsz_gu=-E*pi.pa.dz_mm*pi.scale end
 end
end
local last_z,last_x,last_y,last_t,jumped={},{},{},{},{}
local diagnostic_plane_hit={}
local detector_crossed={}
local timed_out={}
local grid_jump_count={}
local max_z={}
local step_count={}
function segment.initialize()
 local n=ion_number
 last_z[n],last_x[n],last_y[n],last_t[n]=ion_pz_mm,ion_px_mm,ion_py_mm,ion_time_of_flight
 max_z[n]=ion_pz_mm; step_count[n]=0; diagnostic_plane_hit[n]=false; detector_crossed[n]=false; timed_out[n]=false; grid_jump_count[n]={}
 if trajectory_log_enable~=0 then print('TRACE: ion,t_us,x_mm,y_mm,z_mm,vx_mm_us,vy_mm_us,vz_mm_us,instance,event') end
end
function segment.tstep_adjust()
 if detector_tstep_enable==0 or not detector_z_mm or ion_vz_mm>=-1e-12 then return end
 local dz=ion_pz_mm-detector_z_mm
 if dz<=0 or dz>detector_tstep_window_mm then return end
 local dx,dy=ion_px_mm-detector_x_mm,ion_py_mm-detector_y_mm
 local radial_limit=detector_radius_mm+simion.wb.instances[4].pa.dx_mm
 if dx*dx+dy*dy>radial_limit*radial_limit then return end
 local speed_z=-ion_vz_mm
 local dt_to_plane=dz/speed_z
 local dt_max_dz=detector_tstep_max_dz_mm/speed_z
 ion_time_step=math.min(ion_time_step,dt_to_plane,dt_max_dz)
end
function segment.other_actions()
 local n,z,vz=ion_number,ion_pz_mm,ion_vz_mm
 local zp=last_z[n] or z
 max_z[n]=math.max(max_z[n] or z,z)
 step_count[n]=(step_count[n] or 0)+1
 if trajectory_log_enable~=0 and step_count[n]%math.max(1,trajectory_log_stride)==0 then
  print(string.format('TRACE: %d,%.12g,%.12g,%.12g,%.12g,%.12g,%.12g,%.12g,%d,step',n,ion_time_of_flight,ion_px_mm,ion_py_mm,ion_pz_mm,ion_vx_mm,ion_vy_mm,ion_vz_mm,ion_instance))
 end
 if not diagnostic_plane_hit[n] and zp>diagnostic_return_plane_z_mm and z<=diagnostic_return_plane_z_mm and vz<0 then
  diagnostic_plane_hit[n]=true
  if trajectory_log_enable~=0 then
   print(string.format('TRACE: diagnostic_return_plane ion=%d t=%.12g x=%.12g y=%.12g z=%.12g vz=%.12g zmax=%.12g',n,ion_time_of_flight,ion_px_mm,ion_py_mm,ion_pz_mm,ion_vz_mm,max_z[n]))
  end
 end
 for _,g in ipairs(grid_planes()) do
  local override=g.group=='accelerator' and accelerator_grid_epsilon_mm or reflectron_grid_epsilon_mm
  local eps=override>0 and override or ideal_grid_epsilon_mm
  local k=tostring(n)..':'..g.name; local d=vz>=0 and 1 or -1
  local pre,post=g.z-d*eps,g.z+d*eps
  if jumped[k] and math.abs(z-g.z)>4*eps then jumped[k]=nil end
  if inside_grid(g,ion_px_mm,ion_py_mm) and not jumped[k] and ((d>0 and zp<pre and z>=pre) or (d<0 and zp>pre and z<=pre)) then
   if math.abs(vz)<1e-12 then error('grid jump with zero axial velocity') end
   ion_time_of_flight=ion_time_of_flight+math.abs(post-z)/math.abs(vz)
   grid_jump_count[n]=grid_jump_count[n] or {}
   grid_jump_count[n][g.name]=(grid_jump_count[n][g.name] or 0)+1
   ion_pz_mm=post; jumped[k]=true; break
  end
 end
 last_z[n],last_x[n],last_y[n],last_t[n]=ion_pz_mm,ion_px_mm,ion_py_mm,ion_time_of_flight
 if ion_time_of_flight>=diagnostic_max_tof_us then
  timed_out[n]=true; ion_splat=1
  if trajectory_log_enable~=0 then print(string.format('TRACE: timeout ion=%d zmax=%.12g',n,max_z[n])) end
 end
end
function segment.terminate()
 local n=ion_number
 if ion_instance~=4 or timed_out[n] or detector_crossed[n] then return end
 detector_crossed[n]=true
 local raw_t,raw_x,raw_y,raw_z=ion_time_of_flight,ion_px_mm,ion_py_mm,ion_pz_mm
 local dt=0
 if math.abs(ion_vz_mm)>1e-12 then dt=(detector_z_mm-ion_pz_mm)/ion_vz_mm end
 local tc=ion_time_of_flight+dt
 local xc=ion_px_mm+ion_vx_mm*dt
 local yc=ion_py_mm+ion_vy_mm*dt
 local dx,dy=xc-detector_x_mm,yc-detector_y_mm
 local radius=math.sqrt(dx*dx+dy*dy)
 local gc=grid_jump_count[n] or {}
 if trajectory_log_enable~=0 then
  print(string.format('TRACE: detector_splat_raw ion=%d t=%.12g x=%.12g y=%.12g z=%.12g vz=%.12g correction_ns=%.12g',n,raw_t,raw_x,raw_y,raw_z,ion_vz_mm,dt*1000))
  print(string.format('TRACE: detector_crossing ion=%d t=%.12g x=%.12g y=%.12g z=%.12g r=%.12g zmax=%.12g',n,tc,xc,yc,detector_z_mm,radius,max_z[n] or ion_pz_mm))
 end
 assert(radius<=detector_radius_mm+simion.wb.instances[4].pa.dx_mm, 'detector PA splat lies outside the physical disk')
 if trajectory_log_enable~=0 then
  print(string.format('TRACE: detector_hit_entity ion=%d instance=4 jumps grid1=%d grid2=%d entgrid=%d midgrid=%d',n,gc.grid1 or 0,gc.grid2 or 0,gc.entgrid or 0,gc.midgrid or 0))
 end
end
